@prefix cdi: <http://ddialliance.org/Specification/DDI-CDI/1.0/RDF/> .
@prefix sh: <http://www.w3.org/ns/shacl#> .
@prefix xsd: <http://www.w3.org/2001/XMLSchema#> .

[] a sh:ValidationReport ;
    sh:conforms false ;
    sh:result [ a sh:ValidationResult ;
            sh:focusNode <https://example.org/layout/observations.csv> ;
            sh:resultMessage "A DDI-CDI PhysicalSegmentLayout should specify cdi:formats - a reference to the LogicalRecord that this layout encodes" ;
            sh:resultPath cdi:formats ;
            sh:resultSeverity sh:Warning ;
            sh:sourceConstraintComponent sh:MinCountConstraintComponent ;
            sh:sourceShape [ sh:message "A DDI-CDI PhysicalSegmentLayout should specify cdi:formats - a reference to the LogicalRecord that this layout encodes" ;
                    sh:minCount 1 ;
                    sh:path cdi:formats ;
                    sh:severity sh:Warning ] ],
        [ a sh:ValidationResult ;
            sh:focusNode <https://example.org/layout/observations.csv> ;
            sh:resultMessage "A DDI-CDI PhysicalSegmentLayout should reference at least one cdi:has_ValueMapping (ValueMapping or id-reference) describing how a variable is laid out" ;
            sh:resultPath cdi:has_ValueMapping ;
            sh:resultSeverity sh:Warning ;
            sh:sourceConstraintComponent sh:MinCountConstraintComponent ;
            sh:sourceShape [ sh:message "A DDI-CDI PhysicalSegmentLayout should reference at least one cdi:has_ValueMapping (ValueMapping or id-reference) describing how a variable is laid out" ;
                    sh:minCount 1 ;
                    sh:path cdi:has_ValueMapping ;
                    sh:severity sh:Warning ] ],
        [ a sh:ValidationResult ;
            sh:focusNode <https://example.org/layout/observations.csv> ;
            sh:resultMessage "A DDI-CDI PhysicalSegmentLayout should specify cdi:encoding (the character encoding ControlledVocabularyEntry, typically UTF-8)" ;
            sh:resultPath cdi:encoding ;
            sh:resultSeverity sh:Warning ;
            sh:sourceConstraintComponent sh:MinCountConstraintComponent ;
            sh:sourceShape [ sh:message "A DDI-CDI PhysicalSegmentLayout should specify cdi:encoding (the character encoding ControlledVocabularyEntry, typically UTF-8)" ;
                    sh:minCount 1 ;
                    sh:path cdi:encoding ;
                    sh:severity sh:Warning ] ] .

